// Deep Link Configuration
class DeepLinkConfig {
  static const String scheme = 'myapp';

  // Allowlisted routes
  static const Set<String> allowedRoutes = {
    'profile',
    'payment',
    'settings',
    'home',
    'product',
    'campaign',
  };

  // Allowlisted hosts (for https deep links)
  static const Set<String> allowedHosts = {
    'myapp.example.com',
    'www.myapp.example.com',
  };

  // Routes that require authentication
  static const Set<String> authenticatedRoutes = {
    'profile',
    'payment',
    'settings',
  };

  // Privileged actions requiring extra validation
  static const Set<String> privilegedActions = {
    'confirm',
    'delete',
    'transfer',
  };
}

// Parsed deep link representation
class DeepLinkData {
  final String route;
  final String? action;
  final Map<String, String> parameters;
  final String rawUri;

  const DeepLinkData({
    required this.route,
    this.action,
    required this.parameters,
    required this.rawUri,
  });

  @override
  String toString() =>
      'DeepLinkData(route: $route, action: $action, params: $parameters)';
}

// Validation result
class ValidationResult {
  final bool isValid;
  final String? errorMessage;
  final DeepLinkData? data;

  const ValidationResult({
    required this.isValid,
    this.errorMessage,
    this.data,
  });

  factory ValidationResult.success(DeepLinkData data) =>
      ValidationResult(isValid: true, data: data);

  factory ValidationResult.failure(String message) =>
      ValidationResult(isValid: false, errorMessage: message);
}

// Parameter validators
class ParameterValidator {
  // Validate numeric ID (e.g., profile/123)
  static bool isValidId(String? value) {
    if (value == null || value.isEmpty) return false;
    final parsed = int.tryParse(value);
    return parsed != null && parsed > 0 && parsed < 2147483647;
  }

  // Validate alphanumeric string (e.g., campaign codes)
  static bool isValidAlphanumeric(String? value) {
    if (value == null || value.isEmpty) return false;
    return RegExp(r'^[a-zA-Z0-9_-]{1,128}$').hasMatch(value);
  }

  // Validate amount (for payment)
  static bool isValidAmount(String? value) {
    if (value == null || value.isEmpty) return false;
    final parsed = double.tryParse(value);
    return parsed != null && parsed > 0 && parsed < 1000000;
  }

  // Sanitize string parameter - remove any potentially dangerous characters
  static String sanitize(String input) {
    return input.replaceAll(RegExp(r'[^\w\-\.@+]'), '').substring(
          0,
          input.length > 256 ? 256 : input.length,
        );
  }

  // Validate query parameters don't contain injection attempts
  static bool isSafeParameter(String key, String value) {
    // Block common injection patterns
    final dangerousPatterns = [
      RegExp(r'<script', caseSensitive: false),
      RegExp(r'javascript:', caseSensitive: false),
      RegExp(r'data:', caseSensitive: false),
      RegExp(r'vbscript:', caseSensitive: false),
      RegExp(r'on\w+=', caseSensitive: false),
      RegExp(r'[\x00-\x1f]'), // Control characters
    ];

    for (final pattern in dangerousPatterns) {
      if (pattern.hasMatch(key) || pattern.hasMatch(value)) {
        return false;
      }
    }

    // Limit parameter length
    if (key.length > 64 || value.length > 512) {
      return false;
    }

    return true;
  }
}

// Route-specific parameter validation rules
class RouteParameterRules {
  static ValidationResult validateRouteParameters(DeepLinkData data) {
    switch (data.route) {
      case 'profile':
        return _validateProfileParams(data);
      case 'payment':
        return _validatePaymentParams(data);
      case 'product':
        return _validateProductParams(data);
      case 'campaign':
        return _validateCampaignParams(data);
      case 'settings':
      case 'home':
        return ValidationResult.success(data);
      default:
        return ValidationResult.failure('Unknown route: ${data.route}');
    }
  }

  static ValidationResult _validateProfileParams(DeepLinkData data) {
    final userId = data.parameters['id'];
    if (userId == null) {
      return ValidationResult.failure('Profile route requires an id parameter');
    }
    if (!ParameterValidator.isValidId(userId)) {
      return ValidationResult.failure('Invalid profile id: must be a positive integer');
    }
    return ValidationResult.success(data);
  }

  static ValidationResult _validatePaymentParams(DeepLinkData data) {
    final action = data.action;
    if (action != null && !DeepLinkConfig.privilegedActions.contains(action)) {
      return ValidationResult.failure('Invalid payment action: $action');
    }

    if (action == 'confirm') {
      final transactionId = data.parameters['transaction_id'];
      if (transactionId == null ||
          !ParameterValidator.isValidAlphanumeric(transactionId)) {
        return ValidationResult.failure(
            'Payment confirm requires a valid transaction_id');
      }

      final amount = data.parameters['amount'];
      if (amount != null && !ParameterValidator.isValidAmount(amount)) {
        return ValidationResult.failure('Invalid payment amount');
      }
    }

    return ValidationResult.success(data);
  }

  static ValidationResult _validateProductParams(DeepLinkData data) {
    final productId = data.parameters['id'];
    if (productId != null && !ParameterValidator.isValidId(productId)) {
      return ValidationResult.failure('Invalid product id');
    }
    return ValidationResult.success(data);
  }

  static ValidationResult _validateCampaignParams(DeepLinkData data) {
    final code = data.parameters['code'];
    if (code != null && !ParameterValidator.isValidAlphanumeric(code)) {
      return ValidationResult.failure('Invalid campaign code');
    }
    final source = data.parameters['source'];
    if (source != null && !ParameterValidator.isValidAlphanumeric(source)) {
      return ValidationResult.failure('Invalid campaign source');
    }
    return ValidationResult.success(data);
  }
}

