// Deep Link Handler
class DeepLinkHandler {
  final GlobalKey<NavigatorState> navigatorKey;
  final AuthService authService;

  StreamSubscription? _linkSubscription;
  DeepLinkData? _pendingDeepLink;

  DeepLinkHandler({
    required this.navigatorKey,
    required this.authService,
  });

  // Initialize - handle initial link and listen for incoming links
  Future<void> initialize() async {
    // Handle the initial link (app opened via deep link)
    try {
      final initialLink = await getInitialLink();
      if (initialLink != null) {
        await _handleRawLink(initialLink);
      }
    } catch (e) {
      debugPrint('DeepLinkHandler: Error getting initial link: $e');
    }

    // Listen for incoming links while app is running
    _linkSubscription = linkStream.listen(
      (String? link) {
        if (link != null) {
          _handleRawLink(link);
        }
      },
      onError: (err) {
        debugPrint('DeepLinkHandler: Error in link stream: $err');
      },
    );
  }

  // Parse URI into DeepLinkData
  DeepLinkData? _parseUri(Uri uri) {
    try {
      List<String> pathSegments;

      if (uri.scheme == DeepLinkConfig.scheme) {
        // Custom scheme: myapp://profile/123
        // host = 'profile', pathSegments might contain additional parts
        final allSegments = <String>[
          if (uri.host.isNotEmpty) uri.host,
          ...uri.pathSegments.where((s) => s.isNotEmpty),
        ];
        pathSegments = allSegments;
      } else if (uri.scheme == 'https' || uri.scheme == 'http') {
        // Universal link: https://myapp.example.com/profile/123
        if (!DeepLinkConfig.allowedHosts.contains(uri.host)) {
          debugPrint('DeepLinkHandler: Host not in allowlist: ${uri.host}');
          return null;
        }
        pathSegments =
            uri.pathSegments.where((s) => s.isNotEmpty).toList();
      } else {
        debugPrint('DeepLinkHandler: Unsupported scheme: ${uri.scheme}');
        return null;
      }

      if (pathSegments.isEmpty) {
        debugPrint('DeepLinkHandler: No path segments found');
        return null;
      }

      final route = pathSegments[0].toLowerCase();
      String? action;
      final parameters = <String, String>{};

      // Parse path segments based on route patterns
      // Pattern: route/id or route/action
      if (pathSegments.length >= 2) {
        final secondSegment = pathSegments[1];

        // Check if second segment is a numeric ID
        if (ParameterValidator.isValidId(secondSegment)) {
          parameters['id'] = secondSegment;
        } else if (ParameterValidator.isValidAlphanumeric(secondSegment)) {
          // It's an action like 'confirm'
          action = secondSegment.toLowerCase();
        }
      }

      // Parse additional path segments as id if present after action
      if (pathSegments.length >= 3) {
        final thirdSegment = pathSegments[2];
        if (ParameterValidator.isValidId(thirdSegment)) {
          parameters['id'] = thirdSegment;
        }
      }

      // Parse and validate query parameters
      uri.queryParameters.forEach((key, value) {
        if (ParameterValidator.isSafeParameter(key, value)) {
          parameters[ParameterValidator.sanitize(key)] =
              ParameterValidator.sanitize(value);
        } else {
          debugPrint(
              'DeepLinkHandler: Blocked unsafe parameter: $key');
        }
      });

      return DeepLinkData(
        route: route,
        action: action,
        parameters: parameters,
        rawUri: uri.toString(),
      );
    } catch (e) {
      debugPrint('DeepLinkHandler: Error parsing URI: $e');
      return null;
    }
  }

  // Validate the parsed deep link
  ValidationResult _validate(DeepLinkData data) {
    // Check route is in allowlist
    if (!DeepLinkConfig.allowedRoutes.contains(data.route)) {
      return ValidationResult.failure(
          'Route not in allowlist: ${data.route}');
    }

    // Validate route-specific parameters
    return RouteParameterRules.validateRouteParameters(data);
  }

  // Handle raw link string
  Future<void> _handleRawLink(String link) async {
    debugPrint('DeepLinkHandler: Received link: $link');

    // Limit total URL length
    if (link.length > 2048) {
      debugPrint('DeepLinkHandler: URL too long, ignoring');
      return;
    }

    final uri = Uri.tryParse(link);
    if (uri == null) {
      debugPrint('DeepLinkHandler: Invalid URI');
      return;
    }

    final data = _parseUri(uri);
    if (data == null) {
      debugPrint('DeepLinkHandler: Failed to parse deep link');
      return;
    }

    final validation = _validate(data);
    if (!validation.isValid) {
      debugPrint(
          'DeepLinkHandler: Validation failed: ${validation.errorMessage}');
      return;
    }

    // Check authentication for protected routes
    if (DeepLinkConfig.authenticatedRoutes.contains(data.route)) {
      if (!authService.isAuthenticated) {
        debugPrint(
            'DeepLinkHandler: Route requires auth, storing pending link');
        _pendingDeepLink = data;
        // Navigate to login
        _navigateTo('/login');
        return;
      }
    }

    // Handle privileged actions with extra confirmation
    if (data.action != null &&
        DeepLinkConfig.privilegedActions.contains(data.action)) {
      await _handlePrivilegedAction(data);
      return;
    }

    // Navigate to the route
    _navigateToDeepLink(data);
  }

  // Handle privileged actions that need extra confirmation
  Future<void> _handlePrivilegedAction(DeepLinkData data) async {
    final context = navigatorKey.currentContext;
    if (context == null) return;

    // Show confirmation dialog for privileged actions
    final confirmed = await showDialog<bool>(
      context: context,
      barrierDismissible: false,
      builder: (ctx) => AlertDialog(
        title: const Text('Confirm Action'),
        content: Text(
          'You are about to perform a ${data.action} action on ${data.route}. '
          'Do you want to continue?',
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.of(ctx).pop(false),
            child: const Text('Cancel'),
          ),
          ElevatedButton(
            onPressed: () => Navigator.of(ctx).pop(true),
            child: const Text('Confirm'),
          ),
        ],
      ),
    );

    if (confirmed == true) {
      _navigateToDeepLink(data);
    } else {
      debugPrint('DeepLinkHandler: Privileged action cancelled by user');
    }
  }

  // Navigate to the appropriate route
  void _navigateToDeepLink(DeepLinkData data) {
    debugPrint('DeepLinkHandler: Navigating to $data');

    switch (data.route) {
      case 'profile':
        _navigateTo('/profile', arguments: {
          'userId': data.parameters['id'],
        });
        break;

      case 'payment':
        if (data.action == 'confirm') {
          _navigateTo('/payment/confirm', arguments: {
            'transactionId': data.parameters['transaction_id'],
            'amount': data.parameters['amount'],
          });
        } else {
          _navigateTo('/payment', arguments: data.parameters);
        }
        break;

      case 'product':
        _navigateTo('/product', arguments: {
          'productId': data.parameters['id'],
        });
        break;

      case 'campaign':
        _navigateTo('/campaign', arguments: {
          'code': data.parameters['code'],
          'source': data.parameters['source'],
        });
        break;

      case 'settings':
        _navigateTo('/settings');
        break;

      case 'home':
      default:
        _navigateTo('/home');
        break;
    }
  }

  void _navigateTo(String route, {Map<String, dynamic>? arguments}) {
    final navigator = navigatorKey.currentState;
    if (navigator != null) {
      navigator.pushNamed(route, arguments: arguments);
    } else {
      debugPrint('DeepLinkHandler: Navigator not available');
    }
  }

  // Call this after successful login to process pending deep link
  Future<void> processPendingDeepLink() async {
    if (_pendingDeepLink != null) {
      final data = _pendingDeepLink!;
      _pendingDeepLink = null;

      if (data.action != null &&
          DeepLinkConfig.privilegedActions.contains(data.action)) {
        await _handlePrivilegedAction(data);
      } else {
        _navigateToDeepLink(data);
      }
    }
  }

  bool get hasPendingDeepLink => _pendingDeepLink != null;

  void dispose() {
    _linkSubscription?.cancel();
  }
}

