class MyApp extends StatefulWidget {
  const MyApp({super.key});

  @override
  State<MyApp> createState() => _MyAppState();
}

class _MyAppState extends State<MyApp> {
  final GlobalKey<NavigatorState> _navigatorKey = GlobalKey<NavigatorState>();
  late final SimpleAuthService _authService;
  late final DeepLinkHandler _deepLinkHandler;

  @override
  void initState() {
    super.initState();
    _authService = SimpleAuthService();
    _authService.setAuthenticated(true); // Demo: set as authenticated

    _deepLinkHandler = DeepLinkHandler(
      navigatorKey: _navigatorKey,
      authService: _authService,
    );

    _deepLinkHandler.initialize();
  }

  @override
  void dispose() {
    _deepLinkHandler.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Deep Link Demo',
      navigatorKey: _navigatorKey,
      theme: ThemeData(
        colorScheme: ColorScheme.fromSeed(seedColor: Colors.deepPurple),
        useMaterial3: true,
      ),
      initialRoute: '/home',
      onGenerateRoute: (settings) {
        final args = settings.arguments as Map<String, dynamic>?;

        switch (settings.name) {
          case '/home':
            return MaterialPageRoute(
              builder: (_) => HomeScreen(
                deepLinkHandler: _deepLinkHandler,
                authService: _authService,
              ),
            );
          case '/profile':
            return MaterialPageRoute(
              builder: (_) => ProfileScreen(
                userId: args?['userId'] as String? ?? 'unknown',
              ),
            );
          case '/payment':
            return MaterialPageRoute(
              builder: (_) => PaymentScreen(parameters: args ?? {}),
            );
          case '/payment/confirm':
            return MaterialPageRoute(
              builder: (_) => PaymentConfirmScreen(
                transactionId:
                    args?['transactionId'] as String? ?? 'unknown',
                amount: args?['amount'] as String?,
              ),
            );
          case '/product':
            return MaterialPageRoute(
              builder: (_) => ProductScreen(
                productId: args?['productId'] as String? ?? 'unknown',
              ),
            );
          case '/campaign':
            return MaterialPageRoute(
              builder: (_) => CampaignScreen(
                code: args?['code'] as String?,
                source: args?['source'] as String?,
              ),
            );
          case '/settings':
            return MaterialPageRoute(
              builder: (_) => const SettingsScreen(),
            );
          case '/login':
            return MaterialPageRoute(
              builder: (_) => LoginScreen(
                authService: _authService,
                deepLinkHandler: _deepLinkHandler,
              ),
            );
          default:
            return MaterialPageRoute(
              builder: (_) => const NotFoundScreen(),
            );
        }
      },
    );
  }
}

