            if (code != null) Text('Campaign Code: $code'),
            if (source != null) Text('Source: $source'),
            const SizedBox(height: 16),
            const Text('Welcome! This campaign was triggered via deep link.'),
          ],
        ),
      ),
    );
  }
}

