class LoginScreen extends StatelessWidget {
  final SimpleAuthService authService;
  final DeepLinkHandler deepLinkHandler;

  const LoginScreen({
    super.key,
    required this.authService,
    required this.deepLinkHandler,
  });

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Login'),
        backgroundColor: Colors.red.shade200,
      ),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            const Icon(Icons.lock, size: 80, color: Colors.red),
            const SizedBox(height: 16),
            const Text('Authentication Required'),
            const SizedBox(height: 8),
            if (deepLinkHandler.hasPendingDeepLink)
              const Text(
                'A deep link is pending. Log in to continue.',
                style: TextStyle(color: Colors.orange),
              ),
            const SizedBox(height: 24),
            ElevatedButton(
              onPressed: () {
                authService.setAuthenticated(true);
                Navigator.pop(context);
                deepLinkHandler.processPendingDeepLink();
              },
              child: const Text('Login (Demo)'),
            ),
          ],
        ),
      ),
    );
  }
}

